sql:
SELECT AVG(attendance) AS avg_higher_attendance
FROM games
WHERE attendance > (SELECT AVG(attendance) FROM games);

SELECT AVG(yards_rushing + yards_passing) AS average_total_yards
FROM game_stats
WHERE team_id = 81;

SELECT AVG(attendance) AS average_attendance
FROM games
WHERE away_team_id < home_team_id;

SELECT DISTINCT p.player_name
FROM players p
JOIN games g ON p.team_id = g.away_team_id
WHERE p.total_yards > (
    SELECT AVG(total_yards) FROM players
);

SELECT attendance
FROM games
WHERE game_id = 1;

SELECT COUNT(*) AS total_games_played
FROM games
WHERE season_id = 1;

SELECT AVG(attendance) AS average_attendance
FROM games
WHERE season_id = 1;

external_knowledge:
- 'teams involved in the matches' refers to both the home and away teams;
- 'home teams' are those playing at their own stadium;
- 'visitors' are those playing away from their home stadium.
